package src;

/**
 * The type Game state manager.
 */
//Ez az osztály felel a persistence-ért
public class GameStateManager {

        /**
        * Save game.
        *
        * @param palya the palya
        */
        public void saveGame(Palya palya) {
            // Save csomopontok.txt
            try (java.io.PrintWriter writer = new java.io.PrintWriter("csomopontok.txt")) {
                for (Csomopont cs : palya.getCsomopontok()) {
                    String type = cs.getEpulet() != null ? cs.getEpulet().getClass().getSimpleName() : "Csomopont";
                    writer.println(cs.id + ";" + cs.getX() + ";" + cs.getY() + ";" + type);
                }
            } catch (java.io.FileNotFoundException e) {
                e.printStackTrace();
            }

            // Save szakaszok.txt
            try (java.io.PrintWriter writer = new java.io.PrintWriter("szakaszok.txt")) {
                for (Utszakasz ut : palya.getUtszakaszok()) {
                    String tipus = ut.getClass().getSimpleName();
                    int savokSzama = ut.getSavok().size();
                    writer.println(ut.id + ";" + ut.kezdoCsomopont.id + ";" + ut.vegCsomopont.id + ";" + savokSzama + ";" + tipus);
                }
            } catch (java.io.FileNotFoundException e) {
                e.printStackTrace();
            }

            // Save jarmuvek.txt
            try (java.io.PrintWriter writer = new java.io.PrintWriter("jarmuvek.txt")) {
                for (Jarmu j : palya.getJarmuvek()) {
                    int pozID = j.getAktualisSav() != null ? j.getAktualisSav().getUtszakasz().getVegPont().id : -1;
                    String tipus = j.getClass().getSimpleName();
                    int kotrofejekID = -1;
                    int fuel = 0;
                    int salt = 0;
                    int zuzottKo = 0;
                    int penz = 0;
                    if (j instanceof Hokotro) {
                        Hokotro h = (Hokotro) j;
                        kotrofejekID = h.getAktualisFej() != null ? h.getAktualisFej().id : -1;
                        fuel = h.getUzemanyag().getLiterek();
                        salt = h.getSo().getMennyiseg();
                        zuzottKo = h.getZuzottKo().getMennyiseg();
                        penz = h.getPenz();
                    }
                    writer.println(j.id + ";" + pozID + ";" + tipus + ";" + kotrofejekID + ";" + fuel + ";" + salt + ";" + zuzottKo + ";" + penz);
                }
            } catch (java.io.FileNotFoundException e) {
                e.printStackTrace();
            }
        }

        /**
        * Load game palya.
        *
        * @return the palya
        */
        public Palya loadGame() {
            // Itt implementálhatod a játék állapotának betöltését fájlból vagy adatbázisból
            // Például JSON formátumban olvashatod be a pálya állapotát
            return new Palya(); // Visszatér egy új pályával, helyettesítsd a tényleges betöltéssel
        }
}

package src;

/**
 * The type Game state manager.
 */
//Ez az osztály felel a persistence-ért
public class GameStateManager {

        /**
        * Save game.
        *
        * @param palya the palya
        */
        public void saveGame(Palya palya) {
            // Save csomopontok.txt
            try (java.io.PrintWriter writer = new java.io.PrintWriter("csomopontok.txt")) {
                for (Csomopont cs : palya.getCsomopontok()) {
                    String type = cs.getEpulet() != null ? cs.getEpulet().getClass().getSimpleName() : "Csomopont";
                    writer.println(cs.id + ";" + cs.getX() + ";" + cs.getY() + ";" + type);
                }
            } catch (java.io.FileNotFoundException e) {
                e.printStackTrace();
            }

            // Save szakaszok.txt
            try (java.io.PrintWriter writer = new java.io.PrintWriter("szakaszok.txt")) {
                for (Utszakasz ut : palya.getUtszakaszok()) {
                    String tipus = ut.getClass().getSimpleName();
                    int savokSzama = ut.getSavok().size();
                    writer.println(ut.id + ";" + ut.kezdoCsomopont.id + ";" + ut.vegCsomopont.id + ";" + savokSzama + ";" + tipus);
                }
            } catch (java.io.FileNotFoundException e) {
                e.printStackTrace();
            }

            // Save jarmuvek.txt
            try (java.io.PrintWriter writer = new java.io.PrintWriter("jarmuvek.txt")) {
                for (Jarmu j : palya.getJarmuvek()) {
                    int pozID = j.getAktualisSav() != null ? j.getAktualisSav().getUtszakasz().getVegPont().id : -1;
                    String tipus = j.getClass().getSimpleName();
                    int kotrofejekID = -1;
                    int fuel = 0;
                    int salt = 0;
                    int zuzottKo = 0;
                    int penz = 0;
                    if (j instanceof Hokotro) {
                        Hokotro h = (Hokotro) j;
                        kotrofejekID = h.getAktualisFej() != null ? h.getAktualisFej().id : -1;
                        fuel = h.getUzemanyag().getLiterek();
                        salt = h.getSo().getMennyiseg();
                        zuzottKo = h.getZuzottKo().getMennyiseg();
                        penz = h.getPenz();
                    }
                    writer.println(j.id + ";" + pozID + ";" + tipus + ";" + kotrofejekID + ";" + fuel + ";" + salt + ";" + zuzottKo + ";" + penz);
                }
            } catch (java.io.FileNotFoundException e) {
                e.printStackTrace();
            }
        }

        /**
        * Load game palya.
        *
        * @return the palya
        */
        public Palya loadGame() {
            ArrayList<Csomopont> csomopontok = new ArrayList<>();
            ArrayList<Utszakasz> utszakaszok = new ArrayList<>();
            ArrayList<Jarmu> jarmuvek = new ArrayList<>();
            java.util.HashMap<Integer, Csomopont> csomopontMap = new java.util.HashMap<>();
            java.util.HashMap<Integer, Utszakasz> utszakaszMap = new java.util.HashMap<>();
            java.util.HashMap<Integer, Jarmu> jarmuMap = new java.util.HashMap<>();

            // Load csomopontok
            try (java.io.BufferedReader reader = new java.io.BufferedReader(new java.io.FileReader("csomopontok.txt"))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    String[] parts = line.split(";");
                    int id = Integer.parseInt(parts[0]);
                    int x = Integer.parseInt(parts[1]);
                    int y = Integer.parseInt(parts[2]);
                    String type = parts[3];
                    Csomopont cs = new Csomopont();
                    cs.id = id;
                    cs.setX(x);
                    cs.setY(y);
                    if (!type.equals("Csomopont")) {
                        switch (type) {
                            case "Munkahely":
                                cs.setEpulet(new Munkahely());
                                break;
                            case "Bolt":
                                cs.setEpulet(new Bolt());
                                break;
                            case "Otthon":
                                cs.setEpulet(new Otthon());
                                break;
                        }
                    }
                    csomopontok.add(cs);
                    csomopontMap.put(id, cs);
                }
            } catch (java.io.IOException e) {
                e.printStackTrace();
                return new Palya(); // fallback
            }

            // Update nextId for Csomopont
            Csomopont.nextId = csomopontok.stream().mapToInt(cs -> cs.id).max().orElse(0) + 1;

            // Load szakaszok
            try (java.io.BufferedReader reader = new java.io.BufferedReader(new java.io.FileReader("szakaszok.txt"))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    String[] parts = line.split(";");
                    int id = Integer.parseInt(parts[0]);
                    int kezdoId = Integer.parseInt(parts[1]);
                    int vegId = Integer.parseInt(parts[2]);
                    int savokSzama = Integer.parseInt(parts[3]);
                    String tipus = parts[4];
                    Csomopont kezdo = csomopontMap.get(kezdoId);
                    Csomopont veg = csomopontMap.get(vegId);
                    Utszakasz ut;
                    switch (tipus) {
                        case "Alagut":
                            ut = new Alagut(kezdo, veg);
                            break;
                        case "Hid":
                            ut = new Hid(kezdo, veg);
                            break;
                        default:
                            ut = new Utszakasz(kezdo, veg);
                            break;
                    }
                    ut.id = id;
                    for (int i = 0; i < savokSzama; i++) {
                        ut.getSavok().add(new Sav());
                    }
                    utszakaszok.add(ut);
                    utszakaszMap.put(id, ut);
                }
            } catch (java.io.IOException e) {
                e.printStackTrace();
                return new Palya();
            }

            // Update nextId for Utszakasz
            Utszakasz.nextId = utszakaszok.stream().mapToInt(ut -> ut.id).max().orElse(0) + 1;

            // Load jarmuvek
            try (java.io.BufferedReader reader = new java.io.BufferedReader(new java.io.FileReader("jarmuvek.txt"))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    String[] parts = line.split(";");
                    int id = Integer.parseInt(parts[0]);
                    int pozID = Integer.parseInt(parts[1]);
                    String tipus = parts[2];
                    int kotrofejekID = Integer.parseInt(parts[3]);
                    int fuel = Integer.parseInt(parts[4]);
                    int salt = Integer.parseInt(parts[5]);
                    int zuzottKo = Integer.parseInt(parts[6]);
                    int penz = Integer.parseInt(parts[7]);
                    Jarmu j;
                    if (tipus.equals("Hokotro")) {
                        Hokotro h = new Hokotro();
                        h.id = id;
                        h.getUzemanyag().tankol(fuel - h.getUzemanyag().getLiterek()); // set to fuel
                        h.getSo().setMennyiseg(salt);
                        h.getZuzottKo().setMennyiseg(zuzottKo);
                        h.penz = penz;
                        // TODO: set aktualisFej if kotrofejekID != -1
                        j = h;
                    } else {
                        // Assume Auto
                        Auto a = new Auto(null, null); // TODO: set otthon and munkahely
                        a.id = id;
                        j = a;
                    }
                    // Set position - find a sav in the csomopont
                    if (pozID != -1) {
                        Csomopont cs = csomopontMap.get(pozID);
                        // Find an utszakasz ending at cs
                        for (Utszakasz ut : utszakaszok) {
                            if (ut.getVegPont() == cs && !ut.getSavok().isEmpty()) {
                                j.setAktualisSav(ut.getSavok().get(0));
                                break;
                            }
                        }
                    }
                    jarmuvek.add(j);
                    jarmuMap.put(id, j);
                }
            } catch (java.io.IOException e) {
                e.printStackTrace();
                return new Palya();
            }

            // Update nextId for Jarmu
            Jarmu.nextId = jarmuvek.stream().mapToInt(j -> j.id).max().orElse(0) + 1;

            return new Palya(csomopontok, utszakaszok, jarmuvek);
        }
}

package src;

import java.util.ArrayList;
import java.util.Random;

/**
 * The type Palya.
 */
public class Palya {

    private final int MAX_NODES = 20;
    private final int MAX_CARS = 5;

    private final ArrayList<Csomopont> csomopontok;
    private final ArrayList<Utszakasz> utszakaszok;
    private final ArrayList<Jarmu> jarmuvek;
    private final Random random = new Random();

    /**
     * Instantiates a new Palya.
     */
    public Palya() {
        csomopontok = new ArrayList<>();
        utszakaszok = new ArrayList<>();
        jarmuvek = new ArrayList<>();
        GenerateMap();
    }

    private void GenerateMap() {

        for (int i = 0; i < MAX_NODES; i++) {
            Csomopont csomopont = new Csomopont();
            if (random.nextBoolean()) {
                int type = random.nextInt(3);
                switch (type) {
                    case 0:
                        csomopont.setEpulet(new Munkahely());
                        break;
                    case 1:
                        csomopont.setEpulet(new Bolt());
                        break;
                    case 2:
                        csomopont.setEpulet(new Otthon());
                        break;
                    default:
                        break;
                }
            }
            csomopontok.add(csomopont);
        }

        for (int i = 0; i < MAX_NODES; i++) {
            for (int j = i + 1; j < MAX_NODES; j++) {

                int type = random.nextInt(10);
                switch (type) {
                    case 0, 1:
                        Utszakasz savosUtszakasz = new Utszakasz(csomopontok.get(i), csomopontok.get(j));
                        savosUtszakasz.getSavok().add(new Sav());
                        savosUtszakasz.getSavok().add(new Sav());
                        utszakaszok.add(savosUtszakasz);
                        break;
                    case 2:
                        Utszakasz savosUtszakasz2 = new Utszakasz(csomopontok.get(i), csomopontok.get(j));
                        savosUtszakasz2.getSavok().add(new Sav());
                        savosUtszakasz2.getSavok().add(new Sav());
                        savosUtszakasz2.getSavok().add(new Sav());
                        utszakaszok.add(savosUtszakasz2);
                        break;
                    case 3:
                        Alagut alagut = new Alagut(csomopontok.get(i), csomopontok.get(j));
                        alagut.getSavok().add(new Sav());
                        utszakaszok.add(alagut);
                        break;
                    case 4:
                        Hid hid = new Hid(csomopontok.get(i), csomopontok.get(j));
                        hid.getSavok().add(new Sav());
                        utszakaszok.add(hid);
                        break;
                    default:
                        Utszakasz egySavosUtszakasz = new Utszakasz(csomopontok.get(i), csomopontok.get(j));
                        egySavosUtszakasz.getSavok().add(new Sav());
                        utszakaszok.add(egySavosUtszakasz);
                        break;
                }
                Utszakasz utszakasz = new Utszakasz(csomopontok.get(i), csomopontok.get(j));
                utszakaszok.add(utszakasz);
            }
        }

        for (int i = 0; i < MAX_CARS; i++) {
            Auto auto = generateAuto();
            jarmuvek.add(auto);
        }


    }

    private Auto generateAuto() {
        Epulet start = null;
        Epulet end = null;

        for (int j = 0; j < csomopontok.size(); j++) {
            if (csomopontok.get(j).getEpulet() instanceof Otthon) {
                start = csomopontok.get(j).getEpulet();
                break;
            }
        }

        for (int j = 0; j < csomopontok.size(); j++) {
            if (csomopontok.get(j).getEpulet() instanceof Munkahely) {
                end = csomopontok.get(j).getEpulet();
                break;
            }
        }

        return new Auto(start, end);
    }
}

package src;

import java.util.ArrayList;
import java.util.Random;

/**
 * The type Palya.
 */
public class Palya {

    private final int MAX_NODES = 20;
    private final int MAX_CARS = 5;

    private final ArrayList<Csomopont> csomopontok;
    private final ArrayList<Utszakasz> utszakaszok;
    private final ArrayList<Jarmu> jarmuvek;
    private final Random random = new Random();

    /**
     * Instantiates a new Palya.
     */
    public Palya() {
        csomopontok = new ArrayList<>();
        utszakaszok = new ArrayList<>();
        jarmuvek = new ArrayList<>();
        GenerateMap();
    }

    private void GenerateMap() {

        for (int i = 0; i < MAX_NODES; i++) {
            Csomopont csomopont = new Csomopont();
            csomopont.setX(random.nextInt(1000)); // Random x between 0-999
            csomopont.setY(random.nextInt(1000)); // Random y between 0-999
            if (random.nextBoolean()) {
                int type = random.nextInt(3);
                switch (type) {
                    case 0:
                        csomopont.setEpulet(new Munkahely());
                        break;
                    case 1:
                        csomopont.setEpulet(new Bolt());
                        break;
                    case 2:
                        csomopont.setEpulet(new Otthon());
                        break;
                    default:
                        break;
                }
            }
            csomopontok.add(csomopont);
        }

        for (int i = 0; i < MAX_NODES; i++) {
            for (int j = i + 1; j < MAX_NODES; j++) {

                int type = random.nextInt(10);
                switch (type) {
                    case 0, 1:
                        Utszakasz savosUtszakasz = new Utszakasz(csomopontok.get(i), csomopontok.get(j));
                        savosUtszakasz.getSavok().add(new Sav());
                        savosUtszakasz.getSavok().add(new Sav());
                        utszakaszok.add(savosUtszakasz);
                        break;
                    case 2:
                        Utszakasz savosUtszakasz2 = new Utszakasz(csomopontok.get(i), csomopontok.get(j));
                        savosUtszakasz2.getSavok().add(new Sav());
                        savosUtszakasz2.getSavok().add(new Sav());
                        savosUtszakasz2.getSavok().add(new Sav());
                        utszakaszok.add(savosUtszakasz2);
                        break;
                    case 3:
                        Alagut alagut = new Alagut(csomopontok.get(i), csomopontok.get(j));
                        alagut.getSavok().add(new Sav());
                        utszakaszok.add(alagut);
                        break;
                    case 4:
                        Hid hid = new Hid(csomopontok.get(i), csomopontok.get(j));
                        hid.getSavok().add(new Sav());
                        utszakaszok.add(hid);
                        break;
                    default:
                        Utszakasz egySavosUtszakasz = new Utszakasz(csomopontok.get(i), csomopontok.get(j));
                        egySavosUtszakasz.getSavok().add(new Sav());
                        utszakaszok.add(egySavosUtszakasz);
                        break;
                }
                Utszakasz utszakasz = new Utszakasz(csomopontok.get(i), csomopontok.get(j));
                utszakaszok.add(utszakasz);
            }
        }

        for (int i = 0; i < MAX_CARS; i++) {
            Auto auto = generateAuto();
            jarmuvek.add(auto);
        }


    }

    private Auto generateAuto() {
        Epulet start = null;
        Epulet end = null;

        for (int j = 0; j < csomopontok.size(); j++) {
            if (csomopontok.get(j).getEpulet() instanceof Otthon) {
                start = csomopontok.get(j).getEpulet();
                break;
            }
        }

        for (int j = 0; j < csomopontok.size(); j++) {
            if (csomopontok.get(j).getEpulet() instanceof Munkahely) {
                end = csomopontok.get(j).getEpulet();
                break;
            }
        }

        return new Auto(start, end);
    }
}
